#!/usr/bin/env node
/**
 * Generate city detail pages for all cities in cities-data.js
 * Based on the Hanoi template structure
 */

const fs = require('fs');
const path = require('path');

// Load detailed category descriptions
let CATEGORY_DESCRIPTIONS = {};
try {
  const descPath = path.join(__dirname, '..', 'data', 'category-descriptions.json');
  if (fs.existsSync(descPath)) {
    CATEGORY_DESCRIPTIONS = JSON.parse(fs.readFileSync(descPath, 'utf-8'));
  }
} catch (e) {
  console.warn('Could not load category descriptions:', e.message);
}

